import React from 'react';
import { Route, BrowserRouter as Router, Routes, useNavigate } from 'react-router-dom';
import './App.css';

function App() {
  return (
    <Router>
      <div className="App">
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/heart" element={<Heart />} />
          <Route path="/lung" element={<Lung />} />
        </Routes>
      </div>
    </Router>
  );
}

function Home() {
  const navigate = useNavigate();
  return (
    <div className="home">
      <div className="hero">
        <h1>Welcome to Medical Prediction Tool</h1>
        <p className="subtitle">Advanced AI-powered predictions for heart disease and lung cancer detection</p>
        <p className="description">Select the type of prediction you want to perform:</p>
        <div className="button-container">
          <button className="choice-btn heart-btn" onClick={() => navigate('/heart')}>
            ❤️ Heart Disease Prediction
          </button>
          <button className="choice-btn lung-btn" onClick={() => navigate('/lung')}>
            🫁 Lung Cancer Prediction
          </button>
        </div>
      </div>
    </div>
  );
}

function Heart() {
  const navigate = useNavigate();
  const [formData, setFormData] = React.useState({
    age: '', sex: '', cp: '', trbps: '', chol: '', fbs: '', restecg: '',
    thalach: '', exang: '', oldpeak: '', slope: '', ca: '', thal: ''
  });
  const [result, setResult] = React.useState(null);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:5000/predict-heart', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });
      const data = await response.json();
      setResult(data);
    } catch (error) {
      setResult({ error: 'Failed to get prediction' });
    }
  };

  return (
    <div className="form-container">
      <h2>Heart Disease Prediction</h2>
      <form onSubmit={handleSubmit}>
        <label>Age: <input name="age" placeholder="e.g., 45" value={formData.age} onChange={handleChange} required type="number" /></label>
        <label>Sex: <input name="sex" placeholder="0=Female, 1=Male" value={formData.sex} onChange={handleChange} required type="number" /></label>
        <label>Chest Pain Type: <input name="cp" placeholder="0-3" value={formData.cp} onChange={handleChange} required type="number" /></label>
        <label>Resting Blood Pressure: <input name="trbps" placeholder="e.g., 130" value={formData.trbps} onChange={handleChange} required type="number" /></label>
        <label>Cholesterol: <input name="chol" placeholder="e.g., 200" value={formData.chol} onChange={handleChange} required type="number" /></label>
        <label>Fasting Blood Sugar: <input name="fbs" placeholder="0 or 1" value={formData.fbs} onChange={handleChange} required type="number" /></label>
        <label>Resting ECG: <input name="restecg" placeholder="0-2" value={formData.restecg} onChange={handleChange} required type="number" /></label>
        <label>Max Heart Rate: <input name="thalach" placeholder="e.g., 150" value={formData.thalach} onChange={handleChange} required type="number" /></label>
        <label>Exercise Induced Angina: <input name="exang" placeholder="0 or 1" value={formData.exang} onChange={handleChange} required type="number" /></label>
        <label>ST Depression: <input name="oldpeak" placeholder="e.g., 1.0" value={formData.oldpeak} onChange={handleChange} required type="number" step="0.1" /></label>
        <label>Slope: <input name="slope" placeholder="0-2" value={formData.slope} onChange={handleChange} required type="number" /></label>
        <label>Number of Major Vessels: <input name="ca" placeholder="0-3" value={formData.ca} onChange={handleChange} required type="number" /></label>
        <label>Thalassemia: <input name="thal" placeholder="1-3" value={formData.thal} onChange={handleChange} required type="number" /></label>
        <button type="submit">Predict</button>
      </form>
      {result && (
        <div className="result">
          {result.error ? <p>Error: {result.error}</p> : (
            <>
              <p>Risk Level: {result.risk_level}</p>
              <p>Confidence: {(result.confidence * 100).toFixed(2)}%</p>
            </>
          )}
        </div>
      )}
      <button onClick={() => navigate('/')}>Back</button>
    </div>
  );
}

function Lung() {
  const navigate = useNavigate();
  const [file, setFile] = React.useState(null);
  const [result, setResult] = React.useState(null);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) return;
    const formData = new FormData();
    formData.append('image', file);
    try {
      const response = await fetch('http://localhost:5000/predict-lung', {
        method: 'POST',
        body: formData
      });
      const data = await response.json();
      setResult(data);
    } catch (error) {
      setResult({ error: 'Failed to get prediction' });
    }
  };

  return (
    <div className="form-container">
      <h2>Lung Cancer Prediction</h2>
      <form onSubmit={handleSubmit}>
        <input type="file" accept="image/*" onChange={handleFileChange} required />
        <button type="submit">Predict</button>
      </form>
      {result && (
        <div className="result">
          {result.error ? <p>Error: {result.error}</p> : (
            <>
              <p>Disease: {result.disease}</p>
              <p>Confidence: {(result.confidence * 100).toFixed(2)}%</p>
            </>
          )}
        </div>
      )}
      <button onClick={() => navigate('/')}>Back</button>
    </div>
  );
}

export default App;
